 1	import React, { FC } from 'react';
 2	import { useNavigate } from 'react-router-dom-v5-compat';
 3	
 4	import { MigrationPolicyModelGroupVersionKind } from '@kubevirt-ui/kubevirt-api/console';
 5	import MigrationPolicyModel from '@kubevirt-ui/kubevirt-api/console/models/MigrationPolicyModel';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import {
 8	  K8sVerb,
 9	  ListPageCreateDropdown,
10	  useAccessReview,
11	} from '@openshift-console/dynamic-plugin-sdk';
12	import { Button, Tooltip } from '@patternfly/react-core';
13	
14	import { createItems, migrationPoliciesPageBaseURL } from '../../utils/constants';
15	
16	const MigrationPoliciesCreateButton: FC = () => {
17	  const { t } = useKubevirtTranslation();
18	  const navigate = useNavigate();
19	
20	  const [canCreateMigrationPolicy] = useAccessReview({
21	    group: MigrationPolicyModel.apiGroup,
22	    resource: MigrationPolicyModel.plural,
23	    verb: 'create' as K8sVerb,
24	  });
25	
26	  const onCreate = (type: string) => {
27	    return type === 'form'
28	      ? navigate(`${migrationPoliciesPageBaseURL}/form`)
29	      : navigate(`${migrationPoliciesPageBaseURL}/~new`);
30	  };
31	
32	  if (!canCreateMigrationPolicy) {
33	    return (
34	      <Tooltip
35	        content={t(
36	          'To perform this action you must get permission from your Organization Administrator.',
37	        )}
38	      >
39	        <Button isAriaDisabled>{t('Create MigrationPolicy')}</Button>
40	      </Tooltip>
41	    );
42	  }
43	
44	  return (
45	    <ListPageCreateDropdown
46	      createAccessReview={{ groupVersionKind: MigrationPolicyModelGroupVersionKind }}
47	      items={createItems}
48	      onClick={onCreate}
49	    >
50	      {t('Create MigrationPolicy')}
51	    </ListPageCreateDropdown>
52	  );
53	};
54	
55	export default MigrationPoliciesCreateButton;

